var successfulPairs = function(spells, potions, success) {
    potions = potions.slice().sort((a, b) => a - b);
    const m = potions.length;
    const res = [];
    for (const s of spells) {
        let lo = 0, hi = m;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (s * potions[mid] >= success) hi = mid;
            else lo = mid + 1;
        }
        res.push(m - lo);
    }
    return res;
};
